1	import { quote, claim } from "./claim-office.js";
2	
3	async function readStdin(): Promise<string> {
4	  const chunks: Buffer[] = [];
5	  for await (const chunk of process.stdin) {
6	    chunks.push(chunk as Buffer);
7	  }
8	  return Buffer.concat(chunks).toString("utf8");
9	}
10	
11	async function main() {
12	  const input = await readStdin();
13	  const scenario = JSON.parse(input);
14	  const yearsWithMHPCO = scenario.customer.yearsWithMHPCO;
15	  const results: Array<Record<string, number>> = [];
16	  const quoteItemsByStep: Record<number, Array<{ type: string; material?: string; enchantment?: number; cursed?: boolean }>> = {};
17	  const priorPaidByPolicy: Record<number, number> = {};
18	  let quoteCounter = 0;
19	
20	  for (let i = 0; i < scenario.steps.length; i++) {
21	    const step = scenario.steps[i];
22	    if (step.op === "quote") {
23	      const result = quote({
24	        customer: { yearsInsured: yearsWithMHPCO, previousContracts: quoteCounter },
25	        items: step.items,
26	      });
27	      quoteItemsByStep[i] = step.items;
28	      quoteCounter++;
29	      results.push({ premium: result.premium });
30	    } else if (step.op === "claim") {
31	      const policyItems = quoteItemsByStep[step.policy];
32	      const priorPaid = priorPaidByPolicy[step.policy] ?? 0;
33	      const result = claim({
34	        items: policyItems,
35	        damages: step.incident.damages,
36	        priorPaid,
37	      });
38	      priorPaidByPolicy[step.policy] = priorPaid + result.payout;
39	      results.push({ payout: result.payout, remainingCap: result.remainingCap });
40	    }
41	  }
42	
43	  process.stdout.write(JSON.stringify({ results }));
44	}
45	
46	main().catch((err) => {
47	  process.stderr.write(String(err.message ?? err) + "\n");
48	  process.exit(1);
49	});
